+/// Rewrite private identifier syntax (`#field`) to legacy-safe identifiers for
+/// runtimes that do not parse private fields. This is intentionally a lexical
+/// compatibility transform, not a semantic class-fields implementation.
+#[allow(clippy::too_many_lines)]
+fn rewrite_legacy_private_identifiers(source: &str) -> String {
+    if !source.contains('#') || !source.is_ascii() {
+        return source.to_string();
+    }
+
+    let bytes = source.as_bytes();
+    let mut out = String::with_capacity(source.len() + 32);
+    let mut i = 0usize;
+    let mut in_single = false;
+    let mut in_double = false;
+    let mut in_template = false;
+    let mut escaped = false;
+    let mut line_comment = false;
+    let mut block_comment = false;
+
+    while i < bytes.len() {
+        let b = bytes[i];
+        let next = bytes.get(i + 1).copied();
+
+        if line_comment {
+            out.push(b as char);
+            if b == b'\n' {
+                line_comment = false;
+            }
+            i += 1;
+            continue;
+        }
+
+        if block_comment {
+            if b == b'*' && next == Some(b'/') {
+                out.push('*');
+                out.push('/');
+                i += 2;
+                block_comment = false;
+                continue;
+            }
+            out.push(b as char);
+            i += 1;
+            continue;
+        }
+
+        if in_single {
+            out.push(b as char);
+            if escaped {
+                escaped = false;
+            } else if b == b'\\' {
+                escaped = true;
+            } else if b == b'\'' {
+                in_single = false;
+            }
+            i += 1;
+            continue;
+        }
+
+        if in_double {
+            out.push(b as char);
+            if escaped {
+                escaped = false;
+            } else if b == b'\\' {
+                escaped = true;
+            } else if b == b'"' {
+                in_double = false;
+            }
+            i += 1;
+            continue;
+        }
+
+        if in_template {
+            out.push(b as char);
+            if escaped {
+                escaped = false;
+            } else if b == b'\\' {
+                escaped = true;
+            } else if b == b'`' {
+                in_template = false;
+            }
+            i += 1;
+            continue;
+        }
+
+        if b == b'/' && next == Some(b'/') {
+            line_comment = true;
+            out.push('/');
+            i += 1;
+            continue;
+        }
+        if b == b'/' && next == Some(b'*') {
+            block_comment = true;
+            out.push('/');
+            i += 1;
+            continue;
+        }
+        if b == b'\'' {
+            in_single = true;
+            out.push('\'');
+            i += 1;
+            continue;
+        }
+        if b == b'"' {
+            in_double = true;
+            out.push('"');
+            i += 1;
+            continue;
+        }
+        if b == b'`' {
+            in_template = true;
+            out.push('`');
+            i += 1;
+            continue;
+        }
